def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    if not password:
        return False

    # Minimum length requirement for admin passwords
    if len(password) < 12:
        return False

    # Check for character complexity
    has_upper = any(c.isupper() for c in password)
    has_lower = any(c.islower() for c in password)
    has_digit = any(c.isdigit() for c in password)
    has_special = any(not c.isalnum() for c in password)

    if not (has_upper and has_lower and has_digit and has_special):
        return False

    # Check for common weak passwords
    common_passwords = {
        'password', 'admin', '123456', 'letmein', 'welcome', 'monkey',
        'dragon', 'master', 'qwerty', 'abc123', 'password123', 'admin123',
        'iloveyou', 'trustno1', 'sunshine', 'princess', 'football', 'baseball'
    }

    if password.lower() in common_passwords:
        return False

    # Check for sequential patterns (e.g., 123456, abcdef)
    sequential_patterns = ['123456', 'abcdef', 'qwerty', 'asdfgh', 'zxcvbn']
    for pattern in sequential_patterns:
        if pattern in password.lower():
            return False

    return True

