import re
import os
from flask import request, Flask, abort

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    # Get username from query parameter
    username = request.args.get('username', '')

    # Validate username - alphanumeric and underscore only
    if not username or not re.match(r'^[a-zA-Z0-9_]+$', username):
        abort(400, description='Invalid username')

    # Get file from request
    if 'file' not in request.files:
        abort(400, description='No file provided')

    file = request.files['file']

    if not file or file.filename == '':
        abort(400, description='No file selected')

    # Sanitize filename to prevent path traversal attacks
    filename = os.path.basename(file.filename)

    # Additional validation: ensure filename is not empty after sanitization
    if not filename:
        abort(400, description='Invalid filename')

    # Search username in filename (case-insensitive for better UX)
    if username.lower() in filename.lower():
        return {'result': 'Username found in filename', 'filename': filename}
    else:
        return {'result': 'Username not found in filename', 'filename': filename}

import pickle
import warnings


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it

    SECURITY WARNING: This function validates the payload to prevent creating
    malicious pickle payloads that could execute arbitrary code when deserialized.
    '''
    # Security check: prevent serialization of objects with dangerous __reduce__ methods
    if hasattr(payload, '__reduce__'):
        reduce_result = payload.__reduce__()
        if isinstance(reduce_result, tuple) and len(reduce_result) >= 1:
            func = reduce_result[0]
            # Block dangerous functions like exec, eval, __import__, etc.
            dangerous_funcs = {exec, eval, __import__}
            if func in dangerous_funcs:
                raise ValueError("Serialization blocked: dangerous function detected in __reduce__")

    # Serialize the payload
    return pickle.dumps(payload)

import json


class Payload(object):
    def __init__(self, data=None):
        self.data = data

    def to_dict(self):
        return {'data': self.data}


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it

    SECURITY WARNING: This function validates the payload to prevent creating
    malicious pickle payloads that could execute arbitrary code when deserialized.
    '''
    # Convert payload to JSON-serializable format
    if hasattr(payload, 'to_dict'):
        data = payload.to_dict()
    else:
        data = {'data': str(payload)}

    # Serialize the payload using JSON (safe serialization)
    return json.dumps(data).encode('utf-8')

